const ShopifyStyleStore = () => {
  const [cart, setCart] = React.useState([]);
  const [showCart, setShowCart] = React.useState(false);
  const [search, setSearch] = React.useState('');

  const products = [
    { id: 1, name: 'Wireless Headphones', price: 79, image: '🎧', category: 'Audio', stock: 12 },
    { id: 2, name: 'Mechanical Keyboard', price: 129, image: '⌨️', category: 'Peripherals', stock: 8 },
    { id: 3, name: 'USB-C Hub', price: 49, image: '📡', category: 'Accessories', stock: 20 },
    { id: 4, name: '4K Monitor', price: 349, image: '🖥️', category: 'Displays', stock: 5 },
    { id: 5, name: 'Webcam Pro', price: 99, image: '📹', category: 'Video', stock: 15 },
    { id: 6, name: 'Desk Lamp LED', price: 39, image: '💡', category: 'Office', stock: 30 }
  ];

  const addToCart = (product, qty = 1) => {
    setCart(prev => {
      const existing = prev.find(c => c.id === product.id);
      if (existing) {
        return prev.map(c => c.id === product.id ? { ...c, qty: c.qty + qty } : c);
      }
      return [...prev, { ...product, qty }];
    });
  };

  const updateQty = (id, delta) => {
    setCart(prev => prev.map(c => {
      if (c.id !== id) return c;
      const next = Math.max(1, c.qty + delta);
      return { ...c, qty: next };
    }));
  };

  const removeFromCart = (id) => {
    setCart(prev => prev.filter(c => c.id !== id));
  };

  const subtotal = cart.reduce((sum, c) => sum + c.price * c.qty, 0);
  const tax = Math.round(subtotal * 0.08);
  const total = subtotal + tax;

  const filtered = products.filter(p => p.name.toLowerCase().includes(search.toLowerCase()));

  const styles = {
    container: {
      fontFamily: 'system-ui, -apple-system, sans-serif',
      background: '#f8fafc',
      minHeight: '100%',
      color: '#1e293b'
    },
    topbar: {
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'space-between',
      padding: '14px 24px',
      background: '#fff',
      borderBottom: '1px solid #e2e8f0'
    },
    brand: {
      fontSize: 18,
      fontWeight: 800
    },
    search: {
      padding: '8px 14px',
      borderRadius: 8,
      border: '1px solid #cbd5e1',
      fontSize: 14,
      outline: 'none',
      width: 220
    },
    cartBtn: {
      position: 'relative',
      padding: '8px 14px',
      borderRadius: 8,
      border: '1px solid #cbd5e1',
      background: '#fff',
      cursor: 'pointer',
      fontSize: 14,
      fontWeight: 600
    },
    cartBadge: {
      position: 'absolute',
      top: -6,
      right: -6,
      background: '#ef4444',
      color: '#fff',
      fontSize: 10,
      fontWeight: 700,
      width: 18,
      height: 18,
      borderRadius: 999,
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center'
    },
    main: {
      display: 'flex'
    },
    grid: {
      flex: 1,
      padding: 24,
      display: 'grid',
      gridTemplateColumns: 'repeat(auto-fill, minmax(160px, 1fr))',
      gap: 16,
      alignContent: 'start'
    },
    product: {
      background: '#fff',
      borderRadius: 12,
      padding: 16,
      boxShadow: '0 1px 3px rgba(0,0,0,0.06)',
      border: '1px solid #e2e8f0',
      textAlign: 'center'
    },
    productImg: {
      fontSize: 48,
      marginBottom: 10
    },
    productName: {
      fontSize: 14,
      fontWeight: 700,
      marginBottom: 4
    },
    productCat: {
      fontSize: 11,
      color: '#94a3b8',
      marginBottom: 8,
      textTransform: 'uppercase',
      letterSpacing: 0.5
    },
    productPrice: {
      fontSize: 16,
      fontWeight: 700,
      color: '#0f172a',
      marginBottom: 10
    },
    qtyRow: {
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      gap: 8,
      marginBottom: 10
    },
    qtyBtn: {
      width: 28,
      height: 28,
      borderRadius: 6,
      border: '1px solid #cbd5e1',
      background: '#fff',
      cursor: 'pointer',
      fontWeight: 700
    },
    qtyVal: {
      fontWeight: 700,
      fontSize: 14,
      minWidth: 20
    },
    addBtn: {
      padding: '8px 14px',
      borderRadius: 8,
      border: 'none',
      background: '#2563eb',
      color: '#fff',
      fontWeight: 600,
      cursor: 'pointer',
      fontSize: 13,
      width: '100%'
    },
    sidebar: {
      width: 300,
      background: '#fff',
      borderLeft: '1px solid #e2e8f0',
      padding: 20,
      display: showCart ? 'block' : 'none'
    },
    sidebarTitle: {
      fontSize: 16,
      fontWeight: 700,
      marginBottom: 16
    },
    cartItem: {
      display: 'flex',
      alignItems: 'center',
      gap: 10,
      padding: '10px 0',
      borderBottom: '1px solid #f1f5f9'
    },
    cartItemImg: {
      fontSize: 28
    },
    cartItemInfo: {
      flex: 1
    },
    cartItemName: {
      fontSize: 13,
      fontWeight: 600
    },
    cartItemPrice: {
      fontSize: 12,
      color: '#64748b'
    },
    cartQty: {
      display: 'flex',
      alignItems: 'center',
      gap: 6
    },
    cartQtyBtn: {
      width: 22,
      height: 22,
      borderRadius: 4,
      border: '1px solid #cbd5e1',
      background: '#fff',
      cursor: 'pointer',
      fontSize: 12,
      fontWeight: 700
    },
    removeBtn: {
      fontSize: 12,
      color: '#ef4444',
      cursor: 'pointer',
      fontWeight: 600,
      background: 'none',
      border: 'none'
    },
    summary: {
      marginTop: 16,
      paddingTop: 16,
      borderTop: '2px solid #e2e8f0'
    },
    summaryRow: {
      display: 'flex',
      justifyContent: 'space-between',
      fontSize: 14,
      marginBottom: 8,
      color: '#475569'
    },
    summaryTotal: {
      display: 'flex',
      justifyContent: 'space-between',
      fontSize: 16,
      fontWeight: 700,
      marginTop: 8,
      paddingTop: 8,
      borderTop: '1px solid #e2e8f0'
    },
    checkoutBtn: {
      marginTop: 14,
      width: '100%',
      padding: '10px',
      borderRadius: 8,
      border: 'none',
      background: '#0f172a',
      color: '#fff',
      fontWeight: 700,
      cursor: 'pointer',
      fontSize: 14
    },
    empty: {
      color: '#94a3b8',
      fontSize: 14,
      textAlign: 'center',
      padding: 24
    }
  };

  return (
    <div style={styles.container}>
      <div style={styles.topbar}>
        <div style={styles.brand}>🛒 Titan Store</div>
        <input
          style={styles.search}
          placeholder="Search products..."
          value={search}
          onChange={e => setSearch(e.target.value)}
        />
        <button style={styles.cartBtn} onClick={() => setShowCart(!showCart)}>
          Cart {cart.length > 0 && <span style={styles.cartBadge}>{cart.reduce((a, c) => a + c.qty, 0)}</span>}
        </button>
      </div>

      <div style={styles.main}>
        <div style={styles.grid}>
          {filtered.map(p => {
            const [qty, setQty] = React.useState(1);
            return (
              <div key={p.id} style={styles.product}>
                <div style={styles.productImg}>{p.image}</div>
                <div style={styles.productName}>{p.name}</div>
                <div style={styles.productCat}>{p.category}</div>
                <div style={styles.productPrice}>${p.price}</div>
                <div style={styles.qtyRow}>
                  <button style={styles.qtyBtn} onClick={() => setQty(Math.max(1, qty - 1))}>-</button>
                  <span style={styles.qtyVal}>{qty}</span>
                  <button style={styles.qtyBtn} onClick={() => setQty(qty + 1)}>+</button>
                </div>
                <button style={styles.addBtn} onClick={() => addToCart(p, qty)}>Add to Cart</button>
              </div>
            );
          })}
        </div>

        <div style={styles.sidebar}>
          <div style={styles.sidebarTitle}>Your Cart</div>
          {cart.length === 0 ? (
            <div style={styles.empty}>Your cart is empty.</div>
          ) : (
            <>
              {cart.map(c => (
                <div key={c.id} style={styles.cartItem}>
                  <div style={styles.cartItemImg}>{c.image}</div>
                  <div style={styles.cartItemInfo}>
                    <div style={styles.cartItemName}>{c.name}</div>
                    <div style={styles.cartItemPrice}>${c.price} each</div>
                  </div>
                  <div style={styles.cartQty}>
                    <button style={styles.cartQtyBtn} onClick={() => updateQty(c.id, -1)}>-</button>
                    <span style={{ fontSize: 13, fontWeight: 600 }}>{c.qty}</span>
                    <button style={styles.cartQtyBtn} onClick={() => updateQty(c.id, 1)}>+</button>
                  </div>
                  <button style={styles.removeBtn} onClick={() => removeFromCart(c.id)}>✕</button>
                </div>
              ))}
              <div style={styles.summary}>
                <div style={styles.summaryRow}>
                  <span>Subtotal</span>
                  <span>${subtotal}</span>
                </div>
                <div style={styles.summaryRow}>
                  <span>Tax (8%)</span>
                  <span>${tax}</span>
                </div>
                <div style={styles.summaryTotal}>
                  <span>Total</span>
                  <span>${total}</span>
                </div>
                <button style={styles.checkoutBtn}>Checkout</button>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
};
render(<ShopifyStyleStore/>);
